UPDATE public.questions SET
  stimulus_text = 'The purpose of a good introduction is to grab the reader’s attention and make them want to read on. There are several techniques that writers can use to achieve this goal, such as starting with a surprising or thought-provoking statement, using vivid imagery, or asking a question. What does this paragraph most directly explain? Subsequent paragraphs reinforce the same line of reasoning with additional examples, helping readers see how the author connects specific observations to a general claim without overstating certainty.',
